"use client";

import Link from "next/link";
import { Product } from "@/types";

interface ProductCardProps {
  product: Product;
  onAdd?: () => void;
  added?: boolean;
}

export default function ProductCard({ product, onAdd, added }: ProductCardProps) {
  const allergenCount = product.allergens?.length || 0;
  const additiveCount = product.additives?.length || 0;

  return (
    <div className="card rounded-2xl p-3.5 flex gap-3.5">
      {product.image_url ? (
        <img
          src={product.image_url}
          alt={product.name}
          className="w-14 h-14 rounded-xl object-cover flex-shrink-0"
        />
      ) : (
        <div className="w-14 h-14 rounded-xl bg-zinc-900 flex-shrink-0 flex items-center justify-center text-xl">
          🍽
        </div>
      )}
      <div className="flex-1 min-w-0 py-0.5">
        <Link href={`/product/${product.id}`}>
          <h3 className="text-white font-semibold text-[14px] truncate hover:text-blue-300 transition-colors">
            {product.name}
          </h3>
        </Link>
        <p className="text-zinc-600 text-[11px] mt-0.5 truncate">{product.brand}</p>

        <div className="flex items-center gap-1.5 mt-2">
          {allergenCount > 0 && (
            <span className="text-[9px] bg-red-500/10 text-red-400/70 px-2 py-0.5 rounded-md font-semibold tracking-wide">
              {allergenCount} allergen{allergenCount > 1 ? "s" : ""}
            </span>
          )}
          {additiveCount > 0 && (
            <span className="text-[9px] bg-yellow-400/8 text-yellow-400/50 px-2 py-0.5 rounded-md font-semibold tracking-wide">
              {additiveCount} additive{additiveCount > 1 ? "s" : ""}
            </span>
          )}
        </div>
      </div>

      {onAdd && (
        <button
          onClick={(e) => { e.preventDefault(); onAdd(); }}
          disabled={added}
          className={`self-center flex-shrink-0 w-9 h-9 rounded-xl text-sm font-bold transition-all duration-200 active:scale-85 flex items-center justify-center ${
            added
              ? "bg-yellow-400/10 text-yellow-400 border border-yellow-400/15"
              : "bg-white/[0.03] text-zinc-500 hover:text-blue-300 hover:bg-blue-400/10 border border-white/[0.04]"
          }`}
        >
          {added ? "✓" : "+"}
        </button>
      )}
    </div>
  );
}
